/* ── Detect OS ── */
function useDetectedOS() {
  const [os, setOs] = useState(null)
  useEffect(() => {
    const ua = navigator.userAgent.toLowerCase()
    if (ua.includes('win')) setOs('windows')
    else if (ua.includes('mac')) setOs('macos')
    else if (ua.includes('linux')) setOs('linux')
    else setOs('windows')
  }, [])
  return os
}

